     1→import React, { useState, useEffect, useRef, useCallback } from 'react';
     2→import { useSearchParams } from 'react-router-dom';
     3→import { motion, AnimatePresence } from 'framer-motion';
     4→import { format } from 'date-fns';
     5→import {
     6→  Settings as SettingsIcon,
     7→  Clock,
     8→  CheckSquare,
     9→  FileText,
    10→  HardDrive,
    11→  Bot,
    12→  Sliders,
    13→  ChevronRight,
    14→} from 'lucide-react';
    15→import {
    16→  exportBrainFile,
    17→  importBrainFile,
    18→  validateBrainFile,
    19→  formatFileSize,
    20→  isFileSystemAccessSupported,
    21→} from '../services/brainBackup';
    22→import {
    23→  loadPreferences,
    24→  getBackupHistory,
    25→  shouldShowBackupReminder,
    26→  getTimeSinceLastBackup,
    27→  addHistoryEntry,
    28→  type BackupPreferences,
    29→  type BackupHistoryEntry,
    30→} from '../services/backupPreferences';
    31→import { indexedDBService } from '../services/indexedDB';
    32→import { exportToICS, importFromICS, downloadICS, readICSFile } from '../services/icsImportExport';
    33→import { requestNotificationPermission } from '../services/eventReminders';
    34→import { useCalendarStore } from '../stores/useCalendarStore';
    35→import { useTerminalStore } from '../stores/useTerminalStore';
    36→import { BackupSettings } from '../components/BackupSettings';
    37→import { PresetManager } from '../components/PresetManager';
    38→import { PageHeader } from '../components/PageHeader';
    39→import { logger } from '../services/logger';
    40→import { ImportData } from '../widgets/Settings/ImportData';
    41→import { DailyNotesSettings } from '../widgets/Settings/DailyNotesSettings';
    42→import { TemplateSettings } from '../widgets/Settings/TemplateSettings';
    43→import { ExportSettings } from '../widgets/Settings/ExportSettings';
    44→import { AboutSettings } from '../widgets/Settings/AboutSettings';
    45→import { AccountSettings } from '../widgets/Settings/AccountSettings';
    46→import { SiteWideSettings } from '../widgets/Settings/SiteWideSettings';
    47→import { TaskManagementSettings } from '../widgets/Settings/TaskManagementSettings';
    48→import { QuickActionsSection } from '../widgets/Settings/QuickActionsSection';
    49→import { AutoSaveSettings } from '../widgets/Settings/AutoSaveSettings';
    50→import { BackupHistorySection } from '../widgets/Settings/BackupHistorySection';
    51→import { BackupOptionsSection } from '../widgets/Settings/BackupOptionsSection';
    52→import { TimeTrackingPanelSettings } from '../widgets/Settings/TimeTrackingPanelSettings';
    53→import CustomFieldsSettings from '../components/CustomFieldsSettings';
    54→import MemberSettings from '../components/MemberSettings';
    55→import { AutoTrackingSettings } from '../components/AutoTrackingSettings';
    56→
    57→const log = logger.module('Settings');
    58→
    59→/**
    60→ * Settings Tab Configuration
    61→ */
    62→const SETTINGS_TABS = [
    63→  { id: 'general', label: 'General', icon: SettingsIcon },
    64→  { id: 'time', label: 'Time Tracking', icon: Clock },
    65→  { id: 'tasks', label: 'Tasks', icon: CheckSquare },
    66→  { id: 'notes', label: 'Notes & Calendar', icon: FileText },
    67→  { id: 'backup', label: 'Backup & Data', icon: HardDrive },
    68→  { id: 'ai', label: 'AI Terminal', icon: Bot },
    69→  { id: 'advanced', label: 'Advanced', icon: Sliders },
    70→] as const;
    71→
    72→type SettingsTabId = (typeof SETTINGS_TABS)[number]['id'];
    73→
    74→/**
    75→ * Settings Page - Modern Tab-Based Layout
    76→ * Local-first privacy with comprehensive settings management
    77→ */
    78→export const Settings: React.FC = () => {
    79→  const [searchParams, setSearchParams] = useSearchParams();
    80→  const currentTab = (searchParams.get('tab') as SettingsTabId) || 'general';
    81→
    82→  // State management
    83→  const [isExporting, setIsExporting] = useState(false);
    84→  const [isImporting, setIsImporting] = useState(false);
    85→  const [message, setMessage] = useState<{ type: 'success' | 'error' | 'info' | 'warning'; text: string } | null>(null);
    86→
    87→  // Preferences
    88→  const [preferences, setPreferences] = useState<BackupPreferences | null>(null);
    89→  const [backupHistory, setBackupHistory] = useState<BackupHistoryEntry[]>([]);
    90→  const [timeSinceLastBackup, setTimeSinceLastBackup] = useState<string | null>(null);
    91→  const [backupReminder, setBackupReminder] = useState<{ show: boolean; daysSinceLastBackup?: number; message?: string } | null>(null);
    92→
    93→  // Advanced Details
    94→  const [showAdvancedDetails, setShowAdvancedDetails] = useState(false);
    95→  const [storageInfo, setStorageInfo] = useState<{
    96→    usageFormatted: string;
    97→    availableFormatted: string;
    98→    quotaFormatted: string;
    99→    percentUsed: number;
   100→  } | null>(null);
   101→
   102→  // New Browser Warning
   103→  const [showNewBrowserWarning, setShowNewBrowserWarning] = useState(false);
   104→
   105→  // Dashboard Settings modal
   106→  const [showPresetManager, setShowPresetManager] = useState(false);
   107→
   108→  // Calendar Import/Export
   109→  const [isExportingCalendar, setIsExportingCalendar] = useState(false);
   110→  const [isImportingCalendar, setIsImportingCalendar] = useState(false);
   111→  const { events, importEvents } = useCalendarStore();
   112→
   113→  // Notification Permission
   114→  const [notificationPermission, setNotificationPermission] = useState<NotificationPermission>('default');
   115→  const [requestingPermission, setRequestingPermission] = useState(false);
   116→
   117→  // AI Terminal (legacy - for showing warning about existing API key)
   118→  const { apiKey } = useTerminalStore();
   119→
   120→  const icsFileInputRef = useRef<HTMLInputElement>(null);
   121→
   122→  // Check notification permission on mount
   123→  useEffect(() => {
   124→    if ('Notification' in window) {
   125→      setNotificationPermission(Notification.permission);
   126→    }
   127→  }, []);
   128→
   129→  const loadAllData = useCallback(async () => {
   130→    // Load preferences
   131→    const prefs = await loadPreferences();
   132→    setPreferences(prefs);
   133→
   134→    // Load backup history
   135→    const history = await getBackupHistory();
   136→    setBackupHistory(history);
   137→
   138→    // Get time since last backup
   139→    const timeSince = await getTimeSinceLastBackup();
   140→    setTimeSinceLastBackup(timeSince);
   141→
   142→    // Check backup reminder
   143→    const reminder = await shouldShowBackupReminder();
   144→    setBackupReminder(reminder);
   145→
   146→    // Load storage quota info
   147→    try {
   148→      const quota = await indexedDBService.getQuota();
   149→      setStorageInfo(quota);
   150→
   151→      // Check if this is a new browser (no data in IndexedDB)
   152→      const keys = await indexedDBService.getAllKeys();
   153→      const hasAnyData = keys.length > 0;
   154→
   155→      // Show new browser warning if no data AND not dismissed
   156→      const dismissed = localStorage.getItem('new-browser-warning-dismissed');
   157→      if (!hasAnyData && !dismissed) {
   158→        setShowNewBrowserWarning(true);
   159→      }
   160→    } catch (error) {
   161→      log.error('Failed to load storage info', { error });
   162→    }
   163→  }, []);
   164→
   165→  // Load data on mount
   166→  useEffect(() => {
   167→    document.title = 'Settings - Neuman Brain';
   168→    loadAllData();
   169→  }, [loadAllData]);
   170→
   171→  // Handle tab change
   172→  const setTab = (tabId: SettingsTabId) => {
   173→    setSearchParams({ tab: tabId });
   174→  };
   175→
   176→  // Export handler
   177→  const handleExport = async (compressed: boolean = true) => {
   178→    try {
   179→      setIsExporting(true);
   180→      setMessage(null);
   181→
   182→      const result = await exportBrainFile({ compressed, prettyPrint: !compressed });
   183→
   184→      // Add to history
   185→      await addHistoryEntry({
   186→        filename: result.filename,
   187→        size: result.size,
   188→        compressed: result.compressed,
   189→        type: 'manual',
   190→        status: 'success',
   191→      });
   192→
   193→      await loadAllData(); // Refresh
   194→
   195→      const sizeInfo = formatFileSize(result.size);
   196→      const compressionNote = compressed ? ' (compressed)' : '';
   197→      setMessage({
   198→        type: 'success',
   199→        text: `Brain data exported successfully! File size: ${sizeInfo}${compressionNote}`
   200→      });
   201→    } catch (error) {
   202→      setMessage({ type: 'error', text: `Export failed: ${error}` });
   203→    } finally {
   204→      setIsExporting(false);
   205→    }
   206→  };
   207→
   208→  // Import handler
   209→  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
   210→    const file = event.target.files?.[0];
   211→    if (!file) return;
   212→
   213→    try {
   214→      setIsImporting(true);
   215→      setMessage(null);
   216→
   217→      const validation = await validateBrainFile(file);
   218→      if (!validation.valid) {
   219→        setMessage({ type: 'error', text: validation.message });
   220→        return;
   221→      }
   222→
   223→      if (validation.info) {
   224→        setMessage({
   225→          type: 'info',
   226→          text: `Found ${validation.info.itemCount} items (${validation.info.fileSize}) from ${new Date(validation.info.exportDate).toLocaleString()}. Importing...`,
   227→        });
   228→      }
   229→
   230→      const result = await importBrainFile(file);
   231→      if (result.success) {
   232→        setMessage({ type: 'success', text: result.message });
   233→        setTimeout(() => window.location.reload(), 2000);
   234→      } else {
   235→        setMessage({ type: 'error', text: result.message });
   236→      }
   237→    } catch (error) {
   238→      setMessage({ type: 'error', text: `Import failed: ${error}` });
   239→    } finally {
   240→      setIsImporting(false);
   241→    }
   242→  };
   243→
   244→  // Calendar handlers
   245→  const handleExportCalendar = async () => {
   246→    try {
   247→      setIsExportingCalendar(true);
   248→      setMessage(null);
   249→
   250→      const result = exportToICS(events);
   251→
   252→      if (!result.success || !result.data) {
   253→        setMessage({ type: 'error', text: result.error || 'Export failed' });
   254→        return;
   255→      }
   256→
   257→      downloadICS(result.data, `calendar-${format(new Date(), 'yyyy-MM-dd')}.ics`);
   258→
   259→      const eventCount = Object.values(events).reduce((acc, arr) => acc + arr.length, 0);
   260→      setMessage({
   261→        type: 'success',
   262→        text: `Calendar exported successfully! ${eventCount} events saved to .ics file.`
   263→      });
   264→    } catch (error) {
   265→      setMessage({ type: 'error', text: `Calendar export failed: ${error}` });
   266→    } finally {
   267→      setIsExportingCalendar(false);
   268→    }
   269→  };
   270→
   271→  const handleImportCalendarClick = () => {
   272→    icsFileInputRef.current?.click();
   273→  };
   274→
   275→  const handleICSFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
   276→    const file = event.target.files?.[0];
   277→    if (!file) return;
   278→
   279→    try {
   280→      setIsImportingCalendar(true);
   281→      setMessage(null);
   282→
   283→      const icsData = await readICSFile(file);
   284→      const result = importFromICS(icsData);
   285→
   286→      if (!result.success || !result.events) {
   287→        setMessage({ type: 'error', text: result.error || 'Import failed' });
   288→        return;
   289→      }
   290→
   291→      const count = importEvents(result.events);
   292→
   293→      setMessage({
   294→        type: 'success',
   295→        text: `Calendar imported successfully! ${count} events added.`
   296→      });
   297→    } catch (error) {
   298→      setMessage({ type: 'error', text: `Calendar import failed: ${error}` });
   299→    } finally {
   300→      setIsImportingCalendar(false);
   301→      if (icsFileInputRef.current) {
   302→        icsFileInputRef.current.value = '';
   303→      }
   304→    }
   305→  };
   306→
   307→  // Notification permission handler
   308→  const handleRequestNotificationPermission = async () => {
   309→    try {
   310→      setRequestingPermission(true);
   311→      const granted = await requestNotificationPermission();
   312→      setNotificationPermission(granted ? 'granted' : 'denied');
   313→      setMessage({
   314→        type: granted ? 'success' : 'warning',
   315→        text: granted
   316→          ? 'Notifications enabled! You will now receive event reminders.'
   317→          : 'Notification permission denied. You can enable it later in your browser settings.',
   318→      });
   319→    } catch (error) {
   320→      log.error('Failed to request notification permission', { error });
   321→      setMessage({ type: 'error', text: 'Failed to request notification permission' });
   322→    } finally {
   323→      setRequestingPermission(false);
   324→    }
   325→  };
   326→
   327→  if (!preferences) {
   328→    return <div className="p-6">Loading...</div>;
   329→  }
   330→
   331→  return (
   332→    <div className="settings-page min-h-screen">
   333→      {/* Page Header */}
   334→      <PageHeader />
   335→
   336→      {/* Message Banner */}
   337→      <AnimatePresence>
   338→        {message && (
   339→          <motion.div
   340→            initial={{ opacity: 0, y: -10 }}
   341→            animate={{ opacity: 1, y: 0 }}
   342→            exit={{ opacity: 0, y: -10 }}
   343→            className={`mb-6 p-4 rounded-lg ${
   344→              message.type === 'success'
   345→                ? 'bg-status-success-bg dark:bg-status-success-bg-dark text-status-success-text dark:text-status-success-text-dark border border-status-success-border dark:border-status-success-border-dark'
   346→                : message.type === 'error'
   347→                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark'
   348→                : message.type === 'warning'
   349→                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark'
   350→                : 'bg-status-info-bg dark:bg-status-info-bg-dark text-status-info-text dark:text-status-info-text-dark border border-status-info-border dark:border-status-info-border-dark'
   351→            }`}
   352→          >
   353→            {message.text}
   354→          </motion.div>
   355→        )}
   356→      </AnimatePresence>
   357→
   358→      {/* Backup Reminder Banner */}
   359→      {backupReminder?.show && (
   360→        <motion.div
   361→          initial={{ opacity: 0, y: -10 }}
   362→          animate={{ opacity: 1, y: 0 }}
   363→          className="mb-6 p-4 rounded-lg bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark flex items-start gap-3"
   364→        >
   365→          <span className="text-2xl">⚠️</span>
   366→          <div className="flex-1">
   367→            <p className="font-semibold">{backupReminder.message}</p>
   368→            <button
   369→              onClick={() => handleExport(preferences.compressionEnabled)}
   370→              className="mt-2 text-sm underline hover:no-underline"
   371→            >
   372→              Create Backup Now
   373→            </button>
   374→          </div>
   375→        </motion.div>
   376→      )}
   377→
   378→      {/* Main Layout: Sidebar + Content */}
   379→      <div className="flex gap-6">
   380→        {/* Tab Navigation Sidebar */}
   381→        <nav className="w-56 flex-shrink-0 hidden md:block">
   382→          <div className="sticky top-4 space-y-1">
   383→            {SETTINGS_TABS.map((tab) => {
   384→              const Icon = tab.icon;
   385→              const isActive = currentTab === tab.id;
   386→              return (
   387→                <button
   388→                  key={tab.id}
   389→                  onClick={() => setTab(tab.id)}
   390→                  className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-lg text-left transition-all duration-200 ${
   391→                    isActive
   392→                      ? 'bg-accent-magenta/10 dark:bg-accent-cyan/10 text-accent-magenta dark:text-accent-cyan font-medium'
   393→                      : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:text-text-light-primary dark:hover:text-text-dark-primary'
   394→                  }`}
   395→                >
   396→                  <Icon className="w-5 h-5 flex-shrink-0" />
   397→                  <span className="flex-1">{tab.label}</span>
   398→                  {isActive && (
   399→                    <ChevronRight className="w-4 h-4 opacity-50" />
   400→                  )}
   401→                </button>
   402→              );
   403→            })}
   404→          </div>
   405→        </nav>
   406→
   407→        {/* Mobile Tab Selector */}
   408→        <div className="md:hidden mb-4 w-full">
   409→          <select
   410→            value={currentTab}
   411→            onChange={(e) => setTab(e.target.value as SettingsTabId)}
   412→            className="w-full px-4 py-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan"
   413→          >
   414→            {SETTINGS_TABS.map((tab) => (
   415→              <option key={tab.id} value={tab.id}>
   416→                {tab.label}
   417→              </option>
   418→            ))}
   419→          </select>
   420→        </div>
   421→
   422→        {/* Content Area */}
   423→        <div className="flex-1 min-w-0">
   424→          <AnimatePresence mode="wait">
   425→            <motion.div
   426→              key={currentTab}
   427→              initial={{ opacity: 0, x: 10 }}
   428→              animate={{ opacity: 1, x: 0 }}
   429→              exit={{ opacity: 0, x: -10 }}
   430→              transition={{ duration: 0.15 }}
   431→              className="space-y-6"
   432→            >
   433→              {/* General Settings */}
   434→              {currentTab === 'general' && (
   435→                <>
   436→                  <AccountSettings />
   437→                  <SiteWideSettings />
   438→                  <div className="bento-card p-6">
   439→                    <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
   440→                      Dashboard Settings
   441→                    </h2>
   442→                    <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-4">
   443→                      Customize which widgets appear on your dashboard and manage their settings.
   444→                    </p>
   445→
   446→                    <button
   447→                      onClick={() => {
   448→                        window.location.href = '/#customize-widgets';
   449→                      }}
   450→                      className="flex items-center gap-2 px-4 py-2 bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors"
   451→                    >
   452→                      <span>⚙️</span>
   453→                      <span>Customize Dashboard Widgets</span>
   454→                    </button>
   455→
   456→                    <div className="mt-4">
   457→                      <button
   458→                        onClick={() => setShowPresetManager(true)}
   459→                        className="flex items-center gap-2 px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg font-medium transition-colors"
   460→                      >
   461→                        <span>📐</span>
   462→                        <span>Manage Dashboard Presets</span>
   463→                      </button>
   464→                    </div>
   465→                  </div>
   466→                </>
   467→              )}
   468→
   469→              {/* Time Tracking Settings */}
   470→              {currentTab === 'time' && (
   471→                <>
   472→                  <div className="bento-card p-6">
   473→                    <TimeTrackingPanelSettings />
   474→                  </div>
   475→                  <div className="bento-card p-6">
   476→                    <AutoTrackingSettings />
   477→                  </div>
   478→                </>
   479→              )}
   480→
   481→              {/* Task Settings */}
   482→              {currentTab === 'tasks' && (
   483→                <TaskManagementSettings />
   484→              )}
   485→
   486→              {/* Notes & Calendar Settings */}
   487→              {currentTab === 'notes' && (
   488→                <>
   489→                  <div className="bento-card p-6">
   490→                    <DailyNotesSettings />
   491→                  </div>
   492→                  <div className="bento-card p-6">
   493→                    <TemplateSettings />
   494→                  </div>
   495→                  <div className="bento-card p-6">
   496→                    <ExportSettings />
   497→                  </div>
   498→
   499→                  {/* Calendar Import/Export */}
   500→                  <div className="bento-card p-6">
   501→                    <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
   502→                      📅 Calendar Import/Export
   503→                    </h2>
   504→                    <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-6">
   505→                      Import events from Google Calendar or export your events to .ics format.
   506→                    </p>
   507→
   508→                    <div className="space-y-3">
   509→                      <button
   510→                        onClick={handleExportCalendar}
   511→                        disabled={isExportingCalendar}
   512→                        className="w-full px-4 py-3 bg-accent-magenta hover:bg-accent-magenta-hover disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
   513→                      >
   514→                        {isExportingCalendar ? '⏳ Exporting...' : '📤 Export Calendar (.ics)'}
   515→                      </button>
   516→
   517→                      <button
   518→                        onClick={handleImportCalendarClick}
   519→                        disabled={isImportingCalendar}
   520→                        className="w-full px-4 py-3 bg-accent-cyan hover:bg-accent-cyan-hover disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
   521→                      >
   522→                        {isImportingCalendar ? '⏳ Importing...' : '📥 Import Calendar (.ics)'}
   523→                      </button>
   524→
   525→                      <input
   526→                        ref={icsFileInputRef}
   527→                        type="file"
   528→                        accept=".ics,.ical"
   529→                        onChange={handleICSFileSelect}
   530→                        className="hidden"
   531→                      />
   532→                    </div>
   533→                  </div>
   534→
   535→                  {/* Calendar Notifications */}
   536→                  <div className="bento-card p-6">
   537→                    <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
   538→                      🔔 Calendar Notifications
   539→                    </h2>
   540→                    <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-6">
   541→                      Enable browser notifications for event reminders.
   542→                    </p>
   543→
   544→                    <div className="mb-4 p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
   545→                      <div className="flex items-center justify-between">
   546→                        <div>
   547→                          <p className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   548→                            Notification Status
   549→                          </p>
   550→                          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   551→                            {notificationPermission === 'granted' && '✅ Notifications are enabled'}
