   553→                            {notificationPermission === 'default' && '⏸️ Not yet requested'}
   554→                          </p>
   555→                        </div>
   556→                        <span className={`px-3 py-1 text-xs font-medium rounded-full ${
   557→                          notificationPermission === 'granted'
   558→                            ? 'bg-status-success/10 text-status-success'
